#include <bits/stdc++.h>
using namespace std;
#define ll long long
const int N=500005;
struct node
{
	int v;
    double w;
};
vector<node> g[N];
int n;
double dp[N];
void dfs1(int u,int f)
{
	for(int i=0;i<g[u].size();i++)
	{
		int v=g[u][i].v;
		if(f==v) continue;
		dfs1(v,u);
		dp[u]+=dp[v]*(1-dp[u])*g[u][i].w;
	}
}
void dfs2(int u,int f)
{
	for(int i=0;i<g[u].size();i++)
	{
		int v=g[u][i].v;
		if(v==f) continue;
		double p=(1-dp[v])*(dp[u]-dp[v]*g[u][i].w),q=(1-dp[v]*g[u][i].w);
		if(q<=1e-8)
		{
			dfs2(v,u);
			continue;
		}
		dp[v]+=p/q*g[u][i].w;
		dfs2(v,u);
	}
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	cin>>n;
	for(int i=1;i<n;i++)
	{
		int u,v;
		double w;
		cin>>u>>v>>w;
		g[u].push_back(node{v,w/100});
		g[v].push_back(node{u,w/100});
	}
	for(int i=1;i<=n;i++)
	{
		double num;
		cin>>num;
		dp[i]=num/100;
	}
	dfs1(1,0);
	dfs2(1,0);
	double ans=0;
	for(int i=1;i<=n;i++)
	{
		ans+=dp[i];
	}
	cout<<fixed<<setprecision(6)<<ans;
	return 0;
}
